import React from 'react';
import Navbar from './Navbar';
import './Perfil.css';

function Perfil() {
  const usuarioMock = {
    nome: 'Usuário TaskFlow',
    email: 'estudante@taskflow.com',
    função: 'Desenvolvedor Frontend / Aluno'
  };

  return (
    <div>
      <Navbar />
      <div className="perfil-container">
        <div className="perfil-box">
          <h2>Meu Perfil</h2>
          <div className="perfil-avatar">TF</div>
          <div className="perfil-info">
            <p><strong>Nome:</strong> {usuarioMock.nome}</p>
            <p><strong>E-mail:</strong> {usuarioMock.email}</p>
            <p><strong>Função:</strong> {usuarioMock.função}</p>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Perfil;
